216â†’        if (!checkNetworkConnection.invoke()) {
217â†’            return
218â†’        }
219â†’        post.setStatus(DRAFT.toString())
220â†’        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
221â†’
222â†’        val localPostId = LocalId(post.id)
223â†’        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
