288â†’            /*
289â†’             * This is an unexpected action and either it has already been handled or another critical action has
290â†’             * been performed. In either case, safest action is to just ignore it.
291â†’             */
292â†’            return
293â†’        }
294â†’        if (isError) {
295â†’            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
296â†’        }
297â†’        if (isRemoved) {
298â†’            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
299â†’        }
