332â†’    fun handlePostTrashed(localPostId: LocalId, isError: Boolean) {
333â†’        val criticalAction = criticalPostActionTracker.get(localPostId)
334â†’        if (criticalAction != TRASHING_POST && criticalAction != TRASHING_POST_WITH_LOCAL_CHANGES) {
335â†’            /*
336â†’             * This is an unexpected action and either it has already been handled or another critical action has
337â†’             * been performed. In either case, safest action is to just ignore it.
338â†’             */
339â†’            return
340â†’        }
341â†’        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = criticalAction)
342â†’        if (isError) {
343â†’            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
344â†’        } else {
345â†’            val snackBarHolder = when (criticalAction) {
346â†’                TRASHING_POST -> SnackbarMessageHolder(
347â†’                    message = UiStringRes(R.string.post_trashed),
348â†’                    buttonTitle = UiStringRes(R.string.undo),
349â†’                    buttonAction = {
350â†’                        val post = postStore.getPostByLocalPostId(localPostId.value)
351â†’                        if (post != null) {
352â†’                            restorePost(post)
353â†’                        }
354â†’                    }
355â†’                )
356â†’                TRASHING_POST_WITH_LOCAL_CHANGES -> SnackbarMessageHolder(message = UiStringRes(R.string.post_trashed))
357â†’                else -> throw IllegalStateException("Unexpected action in handlePostTrashed(): $criticalAction")
358â†’            }
359â†’            showSnackbar.invoke(snackBarHolder)
360â†’        }
361â†’    }
